#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        int ans = 1;
        for(int d=10; d>=1; --d){
            if(N % d == 0){ ans = d; break; }
        }
        printf("%d\n", ans);
    }
    return 0;
}

